import{_ as l,o as e,c as a,a4 as n}from"./chunks/framework._in6GHBg.js";const c=JSON.parse('{"title":"化学反应原理详解","description":"","frontmatter":{},"headers":[],"relativePath":"chemistry/Chem-Learn-Detail-003-化学反应原理详解-V1.0-20260405.md","filePath":"chemistry/Chem-Learn-Detail-003-化学反应原理详解-V1.0-20260405.md"}'),s={name:"chemistry/Chem-Learn-Detail-003-化学反应原理详解-V1.0-20260405.md"};function i(r,t,o,d,g,p){return e(),a("div",null,[...t[0]||(t[0]=[n(`<h1 id="化学反应原理详解" tabindex="-1">化学反应原理详解 <a class="header-anchor" href="#化学反应原理详解" aria-label="Permalink to &quot;化学反应原理详解&quot;">​</a></h1><p><strong>板块3：热化学 + 反应速率 + 化学平衡 + 电化学（高考压轴题核心）</strong></p><hr><h2 id="学习警告" tabindex="-1">学习警告 <a class="header-anchor" href="#学习警告" aria-label="Permalink to &quot;学习警告&quot;">​</a></h2><p><strong>本板块是高考化学的「分水岭」</strong>：</p><ul><li>学得好：化学成绩80分以上</li><li>学不好：化学成绩60分以下</li></ul><p><strong>核心能力要求</strong>：</p><ul><li>理解抽象概念（平衡、动态、等效）</li><li>掌握图像分析（速率-时间图、转化率-温度图）</li><li>熟练计算（平衡常数、转化率、电极反应）</li></ul><hr><h2 id="第一章-化学反应与能量-热化学" tabindex="-1">第一章：化学反应与能量（热化学） <a class="header-anchor" href="#第一章-化学反应与能量-热化学" aria-label="Permalink to &quot;第一章：化学反应与能量（热化学）&quot;">​</a></h2><h3 id="_1-1-反应热与焓变" tabindex="-1">1.1 反应热与焓变 <a class="header-anchor" href="#_1-1-反应热与焓变" aria-label="Permalink to &quot;1.1 反应热与焓变&quot;">​</a></h3><p><strong>反应热（ΔH）</strong>：化学反应中吸收或放出的热量。</p><ul><li>ΔH &lt; 0：放热反应</li><li>ΔH &gt; 0：吸热反应</li></ul><p><strong>常见反应类型</strong>：</p><table tabindex="0"><thead><tr><th style="text-align:left;">类型</th><th style="text-align:left;">例子</th><th style="text-align:center;">ΔH</th></tr></thead><tbody><tr><td style="text-align:left;">燃烧反应</td><td style="text-align:left;">物质燃烧</td><td style="text-align:center;">&lt; 0（放热）</td></tr><tr><td style="text-align:left;">中和反应</td><td style="text-align:left;">酸碱中和</td><td style="text-align:center;">&lt; 0（放热）</td></tr><tr><td style="text-align:left;">大多数化合</td><td style="text-align:left;">H₂ + Cl₂ = 2HCl</td><td style="text-align:center;">&lt; 0（放热）</td></tr><tr><td style="text-align:left;">大多数分解</td><td style="text-align:left;">CaCO₃ = CaO + CO₂</td><td style="text-align:center;">&gt; 0（吸热）</td></tr><tr><td style="text-align:left;">电离过程</td><td style="text-align:left;">弱电解质电离</td><td style="text-align:center;">&gt; 0（吸热）</td></tr></tbody></table><h3 id="_1-2-热化学方程式" tabindex="-1">1.2 热化学方程式 <a class="header-anchor" href="#_1-2-热化学方程式" aria-label="Permalink to &quot;1.2 热化学方程式&quot;">​</a></h3><p><strong>书写规则</strong>：</p><ol><li>注明物质状态（s、l、g、aq）</li><li>ΔH与化学计量数对应</li><li>放热ΔH为负，吸热ΔH为正</li></ol><p><strong>例子</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>H₂(g) + ½O₂(g) = H₂O(l)  ΔH = -285.8 kJ/mol</span></span>
<span class="line"><span>2H₂(g) + O₂(g) = 2H₂O(l)  ΔH = -571.6 kJ/mol</span></span></code></pre></div><h3 id="_1-3-盖斯定律" tabindex="-1">1.3 盖斯定律 <a class="header-anchor" href="#_1-3-盖斯定律" aria-label="Permalink to &quot;1.3 盖斯定律&quot;">​</a></h3><p><strong>内容</strong>：化学反应的反应热只与始态和终态有关，与途径无关。</p><p><strong>应用</strong>：计算难以直接测量的反应热。</p><p><strong>例题</strong>： 已知： (1) C(s) + O₂(g) = CO₂(g) ΔH₁ = -393.5 kJ/mol (2) CO(g) + ½O₂(g) = CO₂(g) ΔH₂ = -283.0 kJ/mol</p><p>求：C(s) + ½O₂(g) = CO(g) 的ΔH</p><p><strong>解</strong>： (1) - (2) 得： C(s) + ½O₂(g) = CO(g) ΔH = ΔH₁ - ΔH₂ = -393.5 - (-283.0) = -110.5 kJ/mol</p><hr><h2 id="第二章-化学反应速率" tabindex="-1">第二章：化学反应速率 <a class="header-anchor" href="#第二章-化学反应速率" aria-label="Permalink to &quot;第二章：化学反应速率&quot;">​</a></h2><h3 id="_2-1-反应速率的表示" tabindex="-1">2.1 反应速率的表示 <a class="header-anchor" href="#_2-1-反应速率的表示" aria-label="Permalink to &quot;2.1 反应速率的表示&quot;">​</a></h3><p><strong>定义</strong>：单位时间内反应物浓度的减少或生成物浓度的增加。</p><p><strong>公式</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>v = Δc/Δt</span></span>
<span class="line"><span></span></span>
<span class="line"><span>单位：mol/(L·s) 或 mol/(L·min)</span></span></code></pre></div><p><strong>注意</strong>：</p><ul><li>速率总是正值</li><li>不同物质表示的速率之比 = 化学计量数之比</li></ul><p><strong>例子</strong>： 对于 N₂ + 3H₂ ⇌ 2NH₃ v(N₂) : v(H₂) : v(NH₃) = 1 : 3 : 2</p><h3 id="_2-2-影响反应速率的因素" tabindex="-1">2.2 影响反应速率的因素 <a class="header-anchor" href="#_2-2-影响反应速率的因素" aria-label="Permalink to &quot;2.2 影响反应速率的因素&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">因素</th><th style="text-align:left;">影响规律</th><th style="text-align:left;">微观解释</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>浓度</strong></td><td style="text-align:left;">浓度增大，速率加快</td><td style="text-align:left;">单位体积内分子数增多，碰撞机会增加</td></tr><tr><td style="text-align:left;"><strong>压强</strong>（气体）</td><td style="text-align:left;">压强增大，速率加快</td><td style="text-align:left;">相当于浓度增大</td></tr><tr><td style="text-align:left;"><strong>温度</strong></td><td style="text-align:left;">温度升高，速率加快</td><td style="text-align:left;">分子能量增加，活化分子百分数增加</td></tr><tr><td style="text-align:left;"><strong>催化剂</strong></td><td style="text-align:left;">加催化剂，速率加快</td><td style="text-align:left;">降低活化能，活化分子百分数增加</td></tr><tr><td style="text-align:left;"><strong>接触面积</strong></td><td style="text-align:left;">面积增大，速率加快</td><td style="text-align:left;">固体反应物粉碎</td></tr></tbody></table><p><strong>重要结论</strong>：</p><ul><li>温度影响最显著（每升高10℃，速率增大2-4倍）</li><li>催化剂只改变速率，不改变平衡</li></ul><hr><h2 id="第三章-化学平衡-核心难点" tabindex="-1">第三章：化学平衡（核心难点） <a class="header-anchor" href="#第三章-化学平衡-核心难点" aria-label="Permalink to &quot;第三章：化学平衡（核心难点）&quot;">​</a></h2><h3 id="_3-1-可逆反应与化学平衡" tabindex="-1">3.1 可逆反应与化学平衡 <a class="header-anchor" href="#_3-1-可逆反应与化学平衡" aria-label="Permalink to &quot;3.1 可逆反应与化学平衡&quot;">​</a></h3><p><strong>可逆反应</strong>：在同一条件下，既能向正反应方向进行，又能向逆反应方向进行的反应。</p><p><strong>化学平衡状态</strong>：</p><ul><li>正反应速率 = 逆反应速率 ≠ 0（动态平衡）</li><li>各物质浓度保持不变</li></ul><p><strong>平衡特征</strong>：「动、等、定、变」</p><ul><li>动：动态平衡</li><li>等：正逆速率相等</li><li>定：浓度恒定</li><li>变：条件改变，平衡移动</li></ul><h3 id="_3-2-勒夏特列原理" tabindex="-1">3.2 勒夏特列原理 <a class="header-anchor" href="#_3-2-勒夏特列原理" aria-label="Permalink to &quot;3.2 勒夏特列原理&quot;">​</a></h3><p><strong>内容</strong>：如果改变影响平衡的一个条件（浓度、压强、温度），平衡就向能够<strong>减弱</strong>这种改变的方向移动。</p><p><strong>应用规律</strong>：</p><table tabindex="0"><thead><tr><th style="text-align:left;">改变条件</th><th style="text-align:left;">平衡移动方向</th><th style="text-align:left;">结果</th></tr></thead><tbody><tr><td style="text-align:left;">增大反应物浓度</td><td style="text-align:left;">正向移动</td><td style="text-align:left;">反应物浓度减小（但不能回到原值）</td></tr><tr><td style="text-align:left;">减小生成物浓度</td><td style="text-align:left;">正向移动</td><td style="text-align:left;">生成物浓度增大</td></tr><tr><td style="text-align:left;">增大压强（气体）</td><td style="text-align:left;">向气体分子数少的方向</td><td style="text-align:left;">压强减小</td></tr><tr><td style="text-align:left;">升高温度</td><td style="text-align:left;">向吸热方向</td><td style="text-align:left;">温度降低</td></tr><tr><td style="text-align:left;">加催化剂</td><td style="text-align:left;">不移动</td><td style="text-align:left;">正逆速率同倍数增加</td></tr></tbody></table><p><strong>口诀</strong>：「增反减生正移，增压向少，升温向吸」</p><h3 id="_3-3-化学平衡常数-k" tabindex="-1">3.3 化学平衡常数（K） <a class="header-anchor" href="#_3-3-化学平衡常数-k" aria-label="Permalink to &quot;3.3 化学平衡常数（K）&quot;">​</a></h3><p><strong>表达式</strong>： 对于 aA + bB ⇌ cC + dD</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>K = [C]^c [D]^d / [A]^a [B]^b</span></span></code></pre></div><p><strong>重要性质</strong>：</p><ul><li>K只与<strong>温度</strong>有关，与浓度、压强无关</li><li>温度升高，若K增大，则正反应吸热；若K减小，则正反应放热</li></ul><p><strong>计算步骤</strong>（三段式）：</p><ol><li>起始浓度</li><li>变化浓度</li><li>平衡浓度</li><li>代入K表达式</li></ol><p><strong>例题</strong>： N₂ + 3H₂ ⇌ 2NH₃，起始[N₂]=1 mol/L，[H₂]=3 mol/L，平衡[NH₃]=0.5 mol/L，求K。</p><p><strong>解</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>        N₂    +    3H₂    ⇌    2NH₃</span></span>
<span class="line"><span>起始    1          3            0</span></span>
<span class="line"><span>变化   -0.25       -0.75        +0.5</span></span>
<span class="line"><span>平衡    0.75        2.25         0.5</span></span>
<span class="line"><span></span></span>
<span class="line"><span>K = [NH₃]² / ([N₂][H₂]³) = (0.5)² / (0.75 × 2.25³) = ...</span></span></code></pre></div><h3 id="_3-4-等效平衡" tabindex="-1">3.4 等效平衡 <a class="header-anchor" href="#_3-4-等效平衡" aria-label="Permalink to &quot;3.4 等效平衡&quot;">​</a></h3><p><strong>定义</strong>：在相同条件下，同一可逆反应从不同起始状态开始，达到平衡时各物质百分含量相同。</p><p><strong>等效条件</strong>：</p><ul><li>恒温恒容：换算成同一边，物质的量相等</li><li>恒温恒压：换算成同一边，物质的量之比相等</li></ul><p><strong>应用</strong>：简化计算，判断不同起始状态是否等效。</p><h3 id="_3-5-平衡图像分析" tabindex="-1">3.5 平衡图像分析 <a class="header-anchor" href="#_3-5-平衡图像分析" aria-label="Permalink to &quot;3.5 平衡图像分析&quot;">​</a></h3><p><strong>常见图像类型</strong>：</p><ol><li><p><strong>速率-时间图</strong>（v-t图）</p><ul><li>某时刻速率突变 → 浓度/压强改变</li><li>某时刻速率渐变 → 温度改变</li><li>正逆速率同倍数变化 → 加催化剂或压强改变（等体反应）</li></ul></li><li><p><strong>转化率-温度图</strong></p><ul><li>升温转化率增大 → 正反应吸热</li><li>升温转化率减小 → 正反应放热</li></ul></li><li><p><strong>先拐先平数值大</strong></p><ul><li>图像先拐弯的 → 温度高或压强大或加催化剂</li></ul></li></ol><hr><h2 id="第四章-水溶液中的离子平衡" tabindex="-1">第四章：水溶液中的离子平衡 <a class="header-anchor" href="#第四章-水溶液中的离子平衡" aria-label="Permalink to &quot;第四章：水溶液中的离子平衡&quot;">​</a></h2><h3 id="_4-1-弱电解质的电离平衡" tabindex="-1">4.1 弱电解质的电离平衡 <a class="header-anchor" href="#_4-1-弱电解质的电离平衡" aria-label="Permalink to &quot;4.1 弱电解质的电离平衡&quot;">​</a></h3><p><strong>电离平衡</strong>：弱电解质在水溶液中部分电离，存在电离平衡。</p><p><strong>电离方程式</strong>（可逆号）：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>CH₃COOH ⇌ CH₃COO⁻ + H⁺</span></span>
<span class="line"><span>NH₃·H₂O ⇌ NH₄⁺ + OH⁻</span></span></code></pre></div><p><strong>电离度（α）</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>α = 已电离的分子数 / 总分子数 × 100%</span></span></code></pre></div><h3 id="_4-2-水的电离与ph" tabindex="-1">4.2 水的电离与pH <a class="header-anchor" href="#_4-2-水的电离与ph" aria-label="Permalink to &quot;4.2 水的电离与pH&quot;">​</a></h3><p><strong>水的电离</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>H₂O ⇌ H⁺ + OH⁻</span></span>
<span class="line"><span>Kw = [H⁺][OH⁻] = 1×10⁻¹⁴（25℃）</span></span></code></pre></div><p><strong>pH计算</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>pH = -lg[H⁺]</span></span>
<span class="line"><span>pOH = -lg[OH⁻]</span></span>
<span class="line"><span>pH + pOH = 14（25℃）</span></span></code></pre></div><p><strong>溶液酸碱性</strong>：</p><table tabindex="0"><thead><tr><th style="text-align:left;">溶液</th><th style="text-align:center;">[H⁺] vs [OH⁻]</th><th style="text-align:center;">pH范围</th></tr></thead><tbody><tr><td style="text-align:left;">酸性</td><td style="text-align:center;">[H⁺] &gt; [OH⁻]</td><td style="text-align:center;">&lt; 7</td></tr><tr><td style="text-align:left;">中性</td><td style="text-align:center;">[H⁺] = [OH⁻]</td><td style="text-align:center;">= 7</td></tr><tr><td style="text-align:left;">碱性</td><td style="text-align:center;">[H⁺] &lt; [OH⁻]</td><td style="text-align:center;">&gt; 7</td></tr></tbody></table><h3 id="_4-3-盐类水解" tabindex="-1">4.3 盐类水解 <a class="header-anchor" href="#_4-3-盐类水解" aria-label="Permalink to &quot;4.3 盐类水解&quot;">​</a></h3><p><strong>定义</strong>：盐电离出的离子与水电离出的H⁺或OH⁻结合生成弱电解质的反应。</p><p><strong>水解规律</strong>：</p><table tabindex="0"><thead><tr><th style="text-align:center;">盐的类型</th><th style="text-align:center;">例子</th><th style="text-align:left;">水解情况</th><th style="text-align:center;">溶液酸碱性</th></tr></thead><tbody><tr><td style="text-align:center;">强酸强碱盐</td><td style="text-align:center;">NaCl、KNO₃</td><td style="text-align:left;">不水解</td><td style="text-align:center;">中性</td></tr><tr><td style="text-align:center;">强酸弱碱盐</td><td style="text-align:center;">NH₄Cl</td><td style="text-align:left;">NH₄⁺水解</td><td style="text-align:center;">酸性</td></tr><tr><td style="text-align:center;">弱酸强碱盐</td><td style="text-align:center;">CH₃COONa</td><td style="text-align:left;">CH₃COO⁻水解</td><td style="text-align:center;">碱性</td></tr><tr><td style="text-align:center;">弱酸弱碱盐</td><td style="text-align:center;">CH₃COONH₄</td><td style="text-align:left;">双水解</td><td style="text-align:center;">看相对强弱</td></tr></tbody></table><p><strong>水解方程式</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>NH₄⁺ + H₂O ⇌ NH₃·H₂O + H⁺（溶液显酸性）</span></span>
<span class="line"><span>CH₃COO⁻ + H₂O ⇌ CH₃COOH + OH⁻（溶液显碱性）</span></span></code></pre></div><h3 id="_4-4-离子浓度大小比较" tabindex="-1">4.4 离子浓度大小比较 <a class="header-anchor" href="#_4-4-离子浓度大小比较" aria-label="Permalink to &quot;4.4 离子浓度大小比较&quot;">​</a></h3><p><strong>解题工具</strong>：</p><ol><li><strong>电荷守恒</strong>：溶液中正负电荷总量相等</li><li><strong>物料守恒</strong>：某元素的各种形态浓度之和等于初始浓度</li><li><strong>质子守恒</strong>：水电离出的H⁺和OH⁻浓度相等</li></ol><p><strong>例子</strong>：CH₃COONa溶液中</p><ul><li>电荷守恒：[Na⁺] + [H⁺] = [CH₃COO⁻] + [OH⁻]</li><li>物料守恒：[Na⁺] = [CH₃COO⁻] + [CH₃COOH]</li><li>离子浓度：[Na⁺] &gt; [CH₃COO⁻] &gt; [OH⁻] &gt; [H⁺]</li></ul><hr><h2 id="第五章-电化学-高考必考" tabindex="-1">第五章：电化学（高考必考） <a class="header-anchor" href="#第五章-电化学-高考必考" aria-label="Permalink to &quot;第五章：电化学（高考必考）&quot;">​</a></h2><h3 id="_5-1-原电池" tabindex="-1">5.1 原电池 <a class="header-anchor" href="#_5-1-原电池" aria-label="Permalink to &quot;5.1 原电池&quot;">​</a></h3><p><strong>定义</strong>：将化学能转化为电能的装置。</p><p><strong>形成条件</strong>：</p><ol><li>两种活泼性不同的电极</li><li>电解质溶液</li><li>形成闭合回路</li><li>能自发进行氧化还原反应</li></ol><p><strong>工作原理</strong>：</p><ul><li>负极（活泼金属）：失电子，氧化反应</li><li>正极（不活泼金属）：得电子，还原反应</li><li>电子从负极经外电路流向正极</li></ul><p><strong>例子（Cu-Zn原电池）</strong>：</p><ul><li>负极（Zn）：Zn - 2e⁻ = Zn²⁺</li><li>正极（Cu）：2H⁺ + 2e⁻ = H₂↑</li><li>总反应：Zn + 2H⁺ = Zn²⁺ + H₂↑</li></ul><h3 id="_5-2-电解池" tabindex="-1">5.2 电解池 <a class="header-anchor" href="#_5-2-电解池" aria-label="Permalink to &quot;5.2 电解池&quot;">​</a></h3><p><strong>定义</strong>：将电能转化为化学能的装置。</p><p><strong>工作原理</strong>：</p><ul><li>阳极：与电源正极相连，失电子，氧化反应</li><li>阴极：与电源负极相连，得电子，还原反应</li></ul><p><strong>离子放电顺序</strong>：</p><ul><li>阳极（失电子）：活泼金属电极 &gt; S²⁻ &gt; I⁻ &gt; Br⁻ &gt; Cl⁻ &gt; OH⁻ &gt; 含氧酸根</li><li>阴极（得电子）：Ag⁺ &gt; Fe³⁺ &gt; Cu²⁺ &gt; H⁺ &gt; Fe²⁺ &gt; Zn²⁺ &gt; Al³⁺ &gt; Mg²⁺ &gt; Na⁺</li></ul><h3 id="_5-3-原电池-vs-电解池对比" tabindex="-1">5.3 原电池 vs 电解池对比 <a class="header-anchor" href="#_5-3-原电池-vs-电解池对比" aria-label="Permalink to &quot;5.3 原电池 vs 电解池对比&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">对比项</th><th style="text-align:left;">原电池</th><th style="text-align:left;">电解池</th></tr></thead><tbody><tr><td style="text-align:left;">能量转化</td><td style="text-align:left;">化学能→电能</td><td style="text-align:left;">电能→化学能</td></tr><tr><td style="text-align:left;">反应类型</td><td style="text-align:left;">自发进行</td><td style="text-align:left;">外加电源强迫</td></tr><tr><td style="text-align:left;">负极/阳极</td><td style="text-align:left;">负极氧化</td><td style="text-align:left;">阳极氧化</td></tr><tr><td style="text-align:left;">正极/阴极</td><td style="text-align:left;">正极还原</td><td style="text-align:left;">阴极还原</td></tr><tr><td style="text-align:left;">电子流向</td><td style="text-align:left;">负极→正极</td><td style="text-align:left;">电源负极→阴极→阳极→电源正极</td></tr></tbody></table><p><strong>口诀</strong>：「阳氧阴还」（阳极氧化，阴极还原）</p><hr><h2 id="faq-常见错误与解答" tabindex="-1">FAQ（常见错误与解答） <a class="header-anchor" href="#faq-常见错误与解答" aria-label="Permalink to &quot;FAQ（常见错误与解答）&quot;">​</a></h2><h3 id="q1-化学平衡图像题怎么分析" tabindex="-1">Q1：化学平衡图像题怎么分析？ <a class="header-anchor" href="#q1-化学平衡图像题怎么分析" aria-label="Permalink to &quot;Q1：化学平衡图像题怎么分析？&quot;">​</a></h3><p><strong>A</strong>：三步法：</p><ol><li>看坐标轴（什么随什么变化）</li><li>看曲线趋势（增大/减小/先增后减）</li><li>用勒夏特列原理解释</li></ol><p><strong>注意</strong>：「先拐先平数值大」——先拐弯的曲线温度高或压强大。</p><h3 id="q2-等效平衡怎么判断" tabindex="-1">Q2：等效平衡怎么判断？ <a class="header-anchor" href="#q2-等效平衡怎么判断" aria-label="Permalink to &quot;Q2：等效平衡怎么判断？&quot;">​</a></h3><p><strong>A</strong>：</p><ul><li>恒温恒容：换算成方程式同一边，物质的量相等则等效</li><li>恒温恒压：换算成方程式同一边，物质的量之比相等则等效</li><li>技巧：极端假设法（全部转化为反应物或生成物）</li></ul><h3 id="q3-原电池和电解池电极判断总是错怎么办" tabindex="-1">Q3：原电池和电解池电极判断总是错怎么办？ <a class="header-anchor" href="#q3-原电池和电解池电极判断总是错怎么办" aria-label="Permalink to &quot;Q3：原电池和电解池电极判断总是错怎么办？&quot;">​</a></h3><p><strong>A</strong>：记住口诀「阳氧阴还」：</p><ul><li>阳极（原电池负极）：氧化反应，失电子</li><li>阴极（原电池正极）：还原反应，得电子</li></ul><p>电极反应式书写步骤：</p><ol><li>判断电极（阳极/阴极）</li><li>确定反应物（溶液中的离子或电极本身）</li><li>写出产物</li><li>配平（原子守恒+电荷守恒）</li></ol><h3 id="q4-离子浓度大小比较题怎么入手" tabindex="-1">Q4：离子浓度大小比较题怎么入手？ <a class="header-anchor" href="#q4-离子浓度大小比较题怎么入手" aria-label="Permalink to &quot;Q4：离子浓度大小比较题怎么入手？&quot;">​</a></h3><p><strong>A</strong>：</p><ol><li>先写电荷守恒式（必须会）</li><li>判断溶液酸碱性</li><li>考虑电离和水解的程度</li><li>记住常见结论（如CH₃COONa溶液中[Na⁺]&gt;[CH₃COO⁻]&gt;[OH⁻]&gt;[H⁺]）</li></ol><hr><h2 id="文档信息" tabindex="-1">文档信息 <a class="header-anchor" href="#文档信息" aria-label="Permalink to &quot;文档信息&quot;">​</a></h2><p><strong>文档编号</strong>: Chem-Learn-Detail-003<br><strong>板块</strong>: 化学反应原理<br><strong>版本</strong>: V1.0<br><strong>编制日期</strong>: 2026-04-05<br><strong>配套文档</strong>: Chem-Learn-Method-001</p><hr><p><em>化学反应原理是高考化学的核心，务必深入理解。多做题，多画图，多总结。</em></p>`,137)])])}const x=l(s,[["render",i]]);export{c as __pageData,x as default};
